import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"午夜赐福","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/午夜赐福.md","filePath":"4.资源分区/6.技艺及称号/杂项/午夜赐福.md"}'),d={name:"4.资源分区/6.技艺及称号/杂项/午夜赐福.md"};function l(p,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"午夜赐福",tabindex:"-1"},[s("午夜赐福 "),e("a",{class:"header-anchor",href:"#午夜赐福","aria-label":'Permalink to "午夜赐福"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),o('<h1 id="午夜赐福-1" tabindex="-1">午夜赐福 <a class="header-anchor" href="#午夜赐福-1" aria-label="Permalink to &quot;午夜赐福&quot;">​</a></h1><p>午夜赐福<br> 价格：B+2000<br> 本质:魔幻本质<br> 描述：<br> 对于住在杰鲁阶莱西的城堡的大贵族迪米特利马克西莫夫来说，人类只是下等低俗的种族，但他们的鲜血却相当合迪米特利的胃口。迪米特利无比喜欢品尝处女的鲜血，因为这让他想起魔界的美酒,但肆意去捕获人类处女并不符合贵族美德（还可能引发奇怪的传闻），因此迪米特利马克西莫夫只能抓捕那些不长眼来城堡挑战的冒险者满足自己的口欲，但问题是冒险者又大多是男性，所以迪米特利日思夜想，勤学苦练，最终开发出了日后名震世界的―――――超必杀※午夜赐福！</p><p>效果：<br> 结合在一次擒抱攻击检定中，正常对抗，若擒抱成功，则可以你抬手掐住目标的脖颈将对手单手抬起，在下一瞬间，你可以用自己勤学苦练的超级力量，以自由动作将敌人的性别永久改变为女性/雌性，并使她的生理状态为处女（如果她是雌性，那么虽然其性别和外形不会改变，但也会重新变为处女，血的味道也因此改变，具有多重性别的情况由ST判断），若目标是雄性，则这种变化在保留身体外观特色以及年龄特征的的情况下，会尽可能变的符合目标种族的普遍审美，这可能会导致身高体型的变化，但身高的变化范围不可超过目标的原始体型所允许的范围外（例如，一个体积5身高1.9米，名叫豪鬼，拥有漆黑皮肤的雄性肌肉壮汉，可以被变成体积5，身高1.7米小麦肤色身材结实的同龄女性，但不能将其变为1.6米以下（体积4）或者2米以上（体积6）的女性），这是B级诅咒来源的【变形效果】。<br> 这种永久的性别改变效果可以回到主神空间，在仁慈的主神处消耗50分治愈，从而重振雄风。</p><p>若使用者为血族，那么便可以在检定成功，使目标性别改变后，立刻以自由动作，使用天生武器-牙对目标进行一次追加攻击，这次攻击不需要检定，也不会造成伤害，仅有画面效果，旨在用来让使用者狠狠品尝亲手缔造的处女之血，使用者会因此获得持续一轮的3点快速医疗（36医疗点数）并恢复2点血能。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
